// === src/pages/Shop.js ===
import React from 'react';
import './Shop.css';

const shopSections = {
  Plants: [
    {
      name: 'Areca Palm',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/areca_palm.jpg',
      price: 399,
    },
    {
      name: 'ZZ Plant',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/zz_plant.jpg',
      price: 349,
    },
  ],
  Flowers: [
    {
      name: 'Peace Lily',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/peace_lily.jpg',
      price: 299,
    },
    {
      name: 'Anthurium Red',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/anthurium_red.jpg',
      price: 399,
    },
  ],
  Seeds: [
    {
      name: 'Tomato Seeds',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/tomato-seeds.jpg',
      price: 49,
    },
    {
      name: 'Coriander Seeds',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/coriander-seeds.jpg',
      price: 39,
    },
  ],
  Pots: [
    {
      name: 'Ceramic Pot Blue',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/ceramic-pot.jpg',
      price: 199,
    },
    {
      name: 'Terracotta Planter',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/terracotta.jpg',
      price: 149,
    },
  ],
  Decor: [
    {
      name: 'Miniature Fencing',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/fence_decor.jpg',
      price: 79,
    },
    {
      name: 'Wooden Tray',
      image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/wood_tray.jpg',
      price: 129,
    },
  ],
};

const Shop = () => {
  return (
    <div className="shop-container">
      <h2 className="shop-title">Shop All Categories</h2>

      {Object.keys(shopSections).map((section, idx) => (
        <div key={idx} className="shop-section">
          <h3>{section}</h3>
          <div className="shop-grid">
            {shopSections[section].map((product, i) => (
              <div className="product-card" key={i}>
                <img src={product.image} alt={product.name} />
                <h4>{product.name}</h4>
                <p>₹{product.price}</p>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

export default Shop;
